def test_before_after(self):
    f = StringIO()
    collector = []

    def func(item):
        print(item, file=f)
        collector.append(f.getvalue())

    def it():
        yield 'a'
        yield 'b'
        raise RuntimeError('kaboom')

    before = lambda: print('HEADER', file=f)
    after = f.close

